5	
6	const port = Number(process.env.PORT ?? 5733);
7	const sourcemapEnv = process.env.T3CODE_WEB_SOURCEMAP?.trim().toLowerCase();
8	
9	const buildSourcemap =
10	  sourcemapEnv === "0" || sourcemapEnv === "false"
11	    ? false
12	    : sourcemapEnv === "hidden"
13	      ? "hidden"
14	      : true;
15	
16	export default defineConfig({
17	  plugins: [
18	    tanstackRouter(),
19	    react({
20	      babel: {
21	        plugins: [["babel-plugin-react-compiler", { target: "19" }]],
22	      },
23	    }),
24	    tailwindcss(),
25	  ],
26	  optimizeDeps: {
27	    include: ["@pierre/diffs", "@pierre/diffs/react", "@pierre/diffs/worker/worker.js"],
28	  },
29	  define: {
30	    // In dev mode, tell the web app where the WebSocket server lives
31	    "import.meta.env.VITE_WS_URL": JSON.stringify(process.env.VITE_WS_URL ?? ""),
32	  },
33	  experimental: {
34	    enableNativePlugin: true,
35	  },
36	  resolve: {
37	    tsconfigPaths: true,
38	  },
39	  server: {
40	    port,
