import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES_BY_ID,
  THEME_CSS_PROPERTY_KEYS,
  type ThemeId,
} from "@t3tools/contracts";

export type ThemePreference = ThemeId | "system";

type ThemeSnapshot = {
  preference: ThemePreference;
  resolvedThemeId: ThemeId;
  resolvedBase: "light" | "dark";
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function isValidThemeId(value: string): value is ThemeId {
  return value in BUILT_IN_THEMES_BY_ID;
}

function migrateLegacyTheme(): ThemePreference | null {
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (!legacy) return null;

  let migrated: ThemePreference;
  if (legacy === "light") migrated = "t3-light";
  else if (legacy === "dark") migrated = "t3-dark";
  else migrated = "system";

  localStorage.setItem(STORAGE_KEY, migrated);
  localStorage.removeItem(LEGACY_STORAGE_KEY);
  return migrated;
}

function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  if (raw && isValidThemeId(raw)) return raw;

  // Attempt migration from legacy key
  const migrated = migrateLegacyTheme();
  if (migrated) return migrated;

  return "system";
}

function resolveThemeId(pref: ThemePreference): ThemeId {
  if (pref === "system") {
    return getSystemDark() ? "t3-dark" : "t3-light";
  }
  return pref;
}

function applyTheme(pref: ThemePreference, suppressTransitions = false) {
  if (suppressTransitions) {
