import { Schema } from "effect";

// ---------------------------------------------------------------------------
// Theme color map – 25 keys matching the CSS custom properties in index.css
// ---------------------------------------------------------------------------

export interface ThemeColorMap {
  readonly background: string;
  readonly foreground: string;
  readonly card: string;
  readonly "card-foreground": string;
  readonly popover: string;
  readonly "popover-foreground": string;
  readonly primary: string;
  readonly "primary-foreground": string;
  readonly secondary: string;
  readonly "secondary-foreground": string;
  readonly muted: string;
  readonly "muted-foreground": string;
  readonly accent: string;
  readonly "accent-foreground": string;
  readonly destructive: string;
  readonly "destructive-foreground": string;
  readonly border: string;
  readonly input: string;
  readonly ring: string;
  readonly info: string;
  readonly "info-foreground": string;
  readonly success: string;
  readonly "success-foreground": string;
  readonly warning: string;
  readonly "warning-foreground": string;
}

/** Every key in ThemeColorMap, used to iterate when applying CSS variables. */
export const THEME_CSS_PROPERTY_KEYS: ReadonlyArray<keyof ThemeColorMap> = [
  "background",
  "foreground",
  "card",
  "card-foreground",
  "popover",
  "popover-foreground",
  "primary",
  "primary-foreground",
  "secondary",
  "secondary-foreground",
  "muted",
  "muted-foreground",
  "accent",
  "accent-foreground",
  "destructive",
  "destructive-foreground",
  "border",
  "input",
  "ring",
  "info",
  "info-foreground",
  "success",
  "success-foreground",
  "warning",
  "warning-foreground",
] as const;

// ---------------------------------------------------------------------------
// Theme identity
// ---------------------------------------------------------------------------

export const BUILT_IN_THEME_IDS = ["t3-light", "t3-dark", "t3-midnight"] as const;

export const ThemeId = Schema.Literal(...BUILT_IN_THEME_IDS);
export type ThemeId = typeof ThemeId.Type;

// ---------------------------------------------------------------------------
// Theme definition
// ---------------------------------------------------------------------------

export interface ThemeDefinition {
  readonly id: ThemeId;
  readonly name: string;
  readonly base: "light" | "dark";
  readonly colors: ThemeColorMap;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const T3_LIGHT: ThemeDefinition = {
  id: "t3-light",
  name: "T3 Light",
  base: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    card: "#ffffff",
    "card-foreground": "#262626",
    popover: "#ffffff",
    "popover-foreground": "#262626",
    primary: "oklch(0.488 0.217 264)",
    "primary-foreground": "#ffffff",
    secondary: "rgba(0,0,0,0.04)",
    "secondary-foreground": "#262626",
    muted: "rgba(0,0,0,0.04)",
    "muted-foreground": "#6b7280",
    accent: "rgba(0,0,0,0.04)",
