import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES_BY_ID,
  THEME_CSS_PROPERTY_KEYS,
  type ThemeId,
} from "@t3tools/contracts";

export type ThemePreference = ThemeId | "system";

type ThemeSnapshot = {
  preference: ThemePreference;
  resolvedThemeId: ThemeId;
  resolvedBase: "light" | "dark";
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function isValidThemeId(value: string): value is ThemeId {
  return value in BUILT_IN_THEMES_BY_ID;
}

function migrateLegacyTheme(): ThemePreference | null {
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (!legacy) return null;

  let migrated: ThemePreference;
  if (legacy === "light") migrated = "t3-light";
  else if (legacy === "dark") migrated = "t3-dark";
  else migrated = "system";

  localStorage.setItem(STORAGE_KEY, migrated);
  localStorage.removeItem(LEGACY_STORAGE_KEY);
  return migrated;
}

function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  if (raw && isValidThemeId(raw)) return raw;

  // Attempt migration from legacy key
  const migrated = migrateLegacyTheme();
  if (migrated) return migrated;

  return "system";
}

function resolveThemeId(pref: ThemePreference): ThemeId {
  if (pref === "system") {
    return getSystemDark() ? "t3-dark" : "t3-light";
  }
  return pref;
}

function applyTheme(pref: ThemePreference, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const themeId = resolveThemeId(pref);
  const theme = BUILT_IN_THEMES_BY_ID[themeId];

  // Toggle dark class for Tailwind dark variant
  document.documentElement.classList.toggle("dark", theme.base === "dark");

  // Apply all CSS custom properties
  const style = document.documentElement.style;
  for (const key of THEME_CSS_PROPERTY_KEYS) {
    style.setProperty(`--${key}`, theme.colors[key]);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const preference = getStored();
  const systemDark = getSystemDark();
  const resolvedThemeId = resolveThemeId(preference);
  const resolvedBase = BUILT_IN_THEMES_BY_ID[resolvedThemeId].base;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.resolvedThemeId === resolvedThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, resolvedThemeId, resolvedBase, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(snapshot.preference);
  }, [snapshot.preference]);

  return {
    /** The user's preference: a specific theme id or "system". */
    theme: snapshot.preference,
    /** Update the theme preference. */
    setTheme,
    /** Resolved base: "light" | "dark" — backward-compatible with existing consumers. */
    resolvedTheme: snapshot.resolvedBase,
    /** The concrete resolved theme id after system preference resolution. */
    activeThemeId: snapshot.resolvedThemeId,
  } as const;
}

