191	    },
192	    [settings, updateSettings],
193	  );
194	
195	  return (
196	    <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground isolate">
197	      <div className="flex min-h-0 min-w-0 flex-1 flex-col bg-background text-foreground">
